// src/App.js
import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { jwtDecode } from 'jwt-decode'; // Import jwtDecode để giải mã token

// Import các trang chính
import LoginPage from './pages/LoginPage';
import Dashboard from './pages/Dashboard';
import KhaiBaoCoSo from './pages/KhaiBaoCoSo';
import LogoutPage from './pages/LogoutPage';
import Sidebar from './components/Sidebar';
import FarmDetail from './pages/FarmDetail';
import FarmEditPage from './pages/FarmEditPage';

// Import các trang quản lý
// Đảm bảo mỗi import có một tên riêng biệt và rõ ràng
import FarmListPage from './pages/RegisterManageSub2Page'; // Trang quản lý danh sách cơ sở (chung)
import WoodFarmListPage from './pages/RegisterManageSub1Page'; // Trang quản lý danh sách cơ sở gỗ
import UserListPage from './pages/UserListPage'; // Trang quản lý danh sách người dùng
import CustomerListPage from './pages/CustomerListPage'; // Trang quản lý danh sách khách hàng

// Import CSS chung cho dashboard layout
import './Dashboard.css';

// Import ảnh banner cho background
import bannerImage from './assets/images/banner.jpg';

// Import ảnh logo kiểm lâm
import logoKiemLam from './assets/images/logo_kiemlam.png';

/**
 * Component PrivateRoute để bảo vệ các route yêu cầu đăng nhập và quyền.
 * Nó kiểm tra token và vai trò của người dùng trước khi cho phép truy cập.
 * @param {object} props - Các props của component.
 * @param {React.ReactNode} props.children - Các component con được bảo vệ.
 * @param {string[]} [props.allowedRoles] - Mảng các vai trò được phép truy cập route này.
 */
const PrivateRoute = ({ children, allowedRoles }) => {
  const token = localStorage.getItem('token');

  if (!token) {
    // Nếu không có token, chuyển hướng đến trang đăng nhập
    return <Navigate to="/" replace />; // Chuyển hướng về trang login (path="/")
  }

  try {
    const decodedToken = jwtDecode(token);
    const userRole = decodedToken.role;

    // Kiểm tra xem vai trò của người dùng có nằm trong allowedRoles không
    if (allowedRoles && !allowedRoles.includes(userRole)) {
      // Nếu không có quyền, chuyển hướng đến dashboard (hoặc trang không có quyền truy cập)
      return <Navigate to="/dashboard" replace />;
    }
    return children; // Cho phép truy cập nếu có token và quyền hợp lệ
  } catch (error) {
    console.error('Lỗi giải mã token hoặc token không hợp lệ:', error);
    localStorage.removeItem('token'); // Xóa token không hợp lệ
    localStorage.removeItem('role'); // Xóa vai trò
    return <Navigate to="/" replace />; // Chuyển hướng đến trang đăng nhập
  }
};

function App() {
  // State để lưu trữ token và vai trò từ localStorage
  const [token, setToken] = useState(localStorage.getItem('token'));
  const [role, setRole] = useState(localStorage.getItem('role'));

  /**
   * Cập nhật trạng thái xác thực (token và vai trò) và lưu vào localStorage.
   * @param {string} newToken - Token JWT mới.
   * @param {string} newRole - Vai trò mới của người dùng.
   */
  const handleSetAuthStatus = (newToken, newRole) => {
    localStorage.setItem('token', newToken);
    localStorage.setItem('role', newRole);
    setToken(newToken);
    setRole(newRole);
  };

  // useEffect để cập nhật state token và role khi component mount
  useEffect(() => {
    setToken(localStorage.getItem('token'));
    setRole(localStorage.getItem('role'));
  }, []);

  // Biến boolean để kiểm tra xem người dùng đã đăng nhập hay chưa
  const isLoggedIn = !!token;

  // Log trạng thái để debug
  console.log('App.js render: token =', token ? 'Có token' : 'Không có token');
  console.log('App.js render: role =', role);
  console.log('App.js render: isLoggedIn =', isLoggedIn);

  return (
    <Router>
      <div className="app-container">
        {/* Sidebar chỉ hiển thị khi người dùng đã đăng nhập */}
        {isLoggedIn && <Sidebar userRole={role} />}

        {/* Áp dụng class 'logged-in' cho main-layout-content khi đã đăng nhập */}
        <div className={`main-layout-content ${isLoggedIn ? 'logged-in' : ''}`} style={{ '--banner-image-url': `url(${bannerImage})` }}>
          <div className="main-header-banner">
            {/* Div bọc để căn giữa logo và text */}
            <div className="header-content-wrapper">
              <img src={logoKiemLam} alt="Logo Chi cục Kiểm Lâm" className="header-logo" />
              <div className="header-text">
                <h1>CHI CỤC KIỂM LÂM TỈNH ĐỒNG THÁP</h1>
                <h2>QUẢN LÝ LÂM SẢN</h2>
                <h3 className="header-copyright" translate="no">Software copyright: Nguyen Van Phuc &copy;Ver 2025 1.0.0&copy;</h3>
              </div>
            </div>
          </div>

          <div className="route-content-wrapper">
            <Routes>
              {/* Route cho trang đăng nhập (mặc định) */}
              <Route path="/" element={<LoginPage setAuthStatus={handleSetAuthStatus} />} />

              {/* Các route được bảo vệ */}
              <Route
                path="/dashboard"
                element={
                  <PrivateRoute allowedRoles={['admin', 'manager', 'staff']}>
                    <Dashboard />
                  </PrivateRoute>
                }
              />
              <Route
                path="/khai-bao"
                element={
                  <PrivateRoute allowedRoles={['admin', 'manager', 'staff']}>
                    <KhaiBaoCoSo />
                  </PrivateRoute>
                }
              />
              <Route
                path="/admin/farms"
                element={
                  <PrivateRoute allowedRoles={['admin', 'manager']}>
                    <FarmListPage /> {/* Trang quản lý cơ sở chung (RegisterManageSub2Page) */}
                  </PrivateRoute>
                }
              />
              <Route
                path="/admin/wood-farms" // Đường dẫn mới cho trang quản lý cơ sở gỗ
                element={
                  <PrivateRoute allowedRoles={['admin', 'manager']}>
                    <WoodFarmListPage /> {/* Trang quản lý cơ sở gỗ (RegisterManageSub1Page) */}
                  </PrivateRoute>
                }
              />
              <Route
                path="/farm-details/:farmId"
                element={
                  <PrivateRoute allowedRoles={['admin', 'manager', 'staff']}>
                    <FarmDetail />
                  </PrivateRoute>
                }
              />
              <Route
                path="/edit-farm/:farmId"
                element={
                  <PrivateRoute allowedRoles={['admin', 'manager']}>
                    <FarmEditPage />
                  </PrivateRoute>
                }
              />

              {/* Các route quản lý người dùng và khách hàng (chỉ admin) */}
              <Route
                path="/admin/users"
                element={
                  <PrivateRoute allowedRoles={['admin']}>
                    <UserListPage /> {/* Trang quản lý người dùng */}
                  </PrivateRoute>
                }
              />
              <Route
                path="/admin/customers"
                element={
                  <PrivateRoute allowedRoles={['admin']}>
                    <CustomerListPage /> {/* Trang quản lý khách hàng */}
                  </PrivateRoute>
                }
              />

              {/* Route đăng xuất */}
              <Route
                path="/logout"
                element={
                  <PrivateRoute> {/* Không cần allowedRoles vì ai cũng có thể đăng xuất */}
                    <LogoutPage setAuthStatus={handleSetAuthStatus} />
                  </PrivateRoute>
                }
              />

              {/* Route catch-all cho các đường dẫn không khớp */}
              <Route path="*" element={<Navigate to="/dashboard" replace />} />
            </Routes>
          </div>
        </div>
      </div>
    </Router>
  );
}

export default App; // Dòng này rất quan trọng để export component App mặc định
